.xt-root::after { content: "📶 5G 🔋"; position: absolute; top: 14px; right: 24px; font-size: 12px; color: #1C1C1E; letter-spacing: 2px; }
.xt-header { position: relative; display: flex; flex-direction: column; align-items: center; margin-bottom: 12px; }
.xt-header::before { content: ""; position: absolute; top: -44px; left: 50%; transform: translateX(-50%); width: 110px; height: 30px; background: #000; border-radius: 20px; }
