/* 基础组件 */
.xt-text:nth-of-type(1) { background: #E5E5EA; color: #3C3C43; padding: 6px 16px; border-radius: 20px; font-size: 13px; font-weight: 500; text-align: center; margin: 0 auto 20px auto; display: inline-block; }
.xt-bar { background: #FFFFFF; padding: 16px; border-radius: var(--xt-radius); margin-bottom: 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.03); }
.xt-bar-track { background: #E5E5EA; height: 8px; border-radius: 4px; margin-top: 8px; }
.xt-bar-fill { background: linear-gradient(90deg, #FF9500, #FF2D55); border-radius: 4px; }
.xt-grid { display: flex; gap: 12px; margin-bottom: 12px; background: transparent; padding: 0; }
.xt-grid-stat { flex: 1; background: #FFFFFF; border-radius: var(--xt-radius); padding: 16px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.03); display: flex; flex-direction: column-reverse; }
.xt-grid-stat-value { font-size: 15px; font-weight: 600; color: #1C1C1E; margin-top: 4px; }
.xt-grid-stat-label { font-size: 10px; color: var(--xt-text-sub); text-transform: uppercase; font-weight: 700; }
.xt-section-title { font-size: 12px; font-weight: 600; color: var(--xt-text-sub); margin: 16px 0 8px 8px; }
.xt-section-body { background: #FFFFFF; border-radius: var(--xt-radius); padding: 16px; font-size: 14px; line-height: 1.6; margin-bottom: 12px; }

/* =========================================
   聊天记录 (只显示他跟别人的对话)
   ========================================= */
.xt-text:nth-of-type(2) { text-align: center; font-size: 12px; font-weight: 600; color: var(--xt-text-sub); margin-bottom: 12px; padding-top: 8px; }
.xt-text:nth-of-type(2)::before { content: "正在与 [ "; color: #C7C7CC; }
.xt-text:nth-of-type(2)::after { content: " ] 通讯"; color: #C7C7CC; }
.xt-bubbles { display: flex; flex-direction: column; gap: 12px; background: #FFFFFF; padding: 20px 16px; border-radius: var(--xt-radius); margin-bottom: 12px; }
.xt-bubble-left, .xt-bubble-right { max-width: 85%; padding: 10px 16px; border-radius: 20px; font-size: 14px; line-height: 1.5; }
.xt-bubble-left { align-self: flex-start; background: #F2F2F7; color: #1C1C1E; border-bottom-left-radius: 4px; }
.xt-bubble-right { align-self: flex-end; background: var(--xt-accent); color: #FFFFFF; border-bottom-right-radius: 4px; }

/* =========================================
   未发送草稿：专属气泡 (指向你)
   ========================================= */
.xt-section:nth-of-type(1) .xt-section-body {
  background: transparent; border: 1px dashed var(--xt-accent); color: var(--xt-accent);
  border-radius: 20px; border-bottom-right-radius: 4px; /* 像气泡一样有个小尾巴 */
  padding: 14px 16px; font-size: 14px; position: relative; margin-top: 16px;
}
@keyframes typingBlink { 0%, 100% { opacity: 0.3; } 50% { opacity: 1; } }
.xt-section:nth-of-type(1) .xt-section-body::before {
  content: "正在输入..."; position: absolute; top: -22px; right: 4px;
  font-size: 11px; color: var(--xt-text-sub); font-style: italic;
  animation: typingBlink 1.5s infinite;
}

/* 随身物品 */
.xt-section:nth-of-type(2) .xt-list { display: flex; flex-wrap: wrap; gap: 8px; background: transparent; padding: 0; margin-bottom: 12px; }
.xt-section:nth-of-type(2) .xt-list-item { background: #FFFFFF; border: 1px solid #E5E5EA; border-radius: 8px; padding: 8px 12px; font-size: 13px; font-weight: 500; }

/* =========================================
   全新设计：Apple Pay 虚拟黑卡 (绝对生效版)
   ========================================= */
.xt-section:nth-of-type(3) .xt-section-body {
  background: linear-gradient(135deg, #151515 0%, #2c2c2e 100%);
  border-radius: 16px; padding: 24px 20px; color: #FFFFFF;
  box-shadow: 0 10px 20px rgba(0,0,0,0.2);
  position: relative; overflow: hidden; border: none;
}
/* 绘制银行卡金属芯片 */
.xt-section:nth-of-type(3) .xt-section-body::before {
  content: ""; position: absolute; top: 20px; right: 20px;
  width: 38px; height: 28px; background: #D1D1D6; border-radius: 6px; opacity: 0.9;
  background-image: linear-gradient(to right, transparent 40%, #8E8E93 40%, #8E8E93 60%, transparent 60%);
  box-shadow: inset 0 0 4px rgba(0,0,0,0.5);
}
.xt-section:nth-of-type(3) .xt-list { background: transparent; padding: 0; margin: 0; }
.xt-section:nth-of-type(3) .xt-list-item {
  border-bottom: 1px solid rgba(255,255,255,0.1);
  padding: 12px 0; color: #F2F2F7; font-size: 13px; line-height: 1.6;
}
.xt-section:nth-of-type(3) .xt-list-item:last-child { border: none; padding-bottom: 0; }
.xt-section:nth-of-type(3) .xt-list-item::before { content: " Pay"; font-weight: 700; margin-right: 10px; opacity: 0.8; color: #FFF; }

/* 脑容量芯片 */
.xt-section:nth-of-type(4) .xt-list { background: transparent; padding: 0; display: flex; flex-direction: column; gap: 8px; margin-bottom: 12px; }
.xt-section:nth-of-type(4) .xt-list-item { background: #1C1C1E; color: #00FF41; border-radius: 12px; padding: 14px 16px; font-weight: 600; letter-spacing: 1px; }

/* 任务与日志 */
.xt-text:nth-of-type(3) { font-style: italic; color: #FF3B30; text-align: center; margin-bottom: 8px; }
.xt-section:nth-of-type(5) .xt-list { background: #FFFFFF; border-radius: var(--xt-radius); padding: 8px 16px; margin-bottom: 12px; }
.xt-section:nth-of-type(5) .xt-list-item { padding: 10px 0; border-bottom: 0.5px solid #E5E5EA; font-size: 14px; }
